/*
 * hubbub-autogenerated-element-type.c -- a portable, gperf-free replacement for
 * libhubbub's generated treebuilder/autogenerated-element-type.c.
 *
 * libhubbub normally generates that file from treebuilder/element-type.gperf with `gperf`
 * (a perfect-hash lookup). gperf is a HOST build tool we don't have in the Onyx cross
 * environment, so this provides the exact same interface with a plain case-insensitive
 * linear scan -- tag names are short and this is not on a hot path (vs. parsing/layout).
 * The user/netsurf Makefile copies it over the generated path before compiling libhubbub,
 * so the vendored libhubbub stays unpatched. The wordlist mirrors element-type.gperf 1:1;
 * the comparison matches gperf's %ignore-case + %compare-strncmp semantics.
 *
 * Included by treebuilder/element-type.c, which has already included element-type.h
 * (so `struct element_type_map` and the `element_type` enum are in scope).
 */
#include <stddef.h>

static const struct element_type_map wordlist[] = {
	{ "a", A }, { "address", ADDRESS }, { "annotation-xml", ANNOTATION_XML },
	{ "applet", APPLET }, { "area", AREA }, { "article", ARTICLE }, { "aside", ASIDE },
	{ "b", B }, { "base", BASE }, { "basefont", BASEFONT }, { "bgsound", BGSOUND },
	{ "big", BIG }, { "blockquote", BLOCKQUOTE }, { "body", BODY }, { "br", BR },
	{ "button", BUTTON }, { "caption", CAPTION }, { "center", CENTER }, { "col", COL },
	{ "colgroup", COLGROUP }, { "command", COMMAND }, { "dd", DD }, { "desc", DESC },
	{ "details", DETAILS }, { "dialog", DIALOG }, { "dir", DIR }, { "div", DIV },
	{ "dl", DL }, { "dt", DT }, { "em", EM }, { "embed", EMBED }, { "fieldset", FIELDSET },
	{ "figcaption", FIGCAPTION }, { "figure", FIGURE }, { "font", FONT },
	{ "footer", FOOTER }, { "foreignobject", FOREIGNOBJECT }, { "form", FORM },
	{ "frame", FRAME }, { "frameset", FRAMESET }, { "h1", H1 }, { "h2", H2 }, { "h3", H3 },
	{ "h4", H4 }, { "h5", H5 }, { "h6", H6 }, { "head", HEAD }, { "hr", HR },
	{ "html", HTML }, { "i", I }, { "iframe", IFRAME }, { "image", IMAGE }, { "img", IMG },
	{ "input", INPUT }, { "isindex", ISINDEX }, { "li", LI }, { "link", LINK },
	{ "listing", LISTING }, { "malignmark", MALIGNMARK }, { "marquee", MARQUEE },
	{ "math", MATH }, { "menu", MENU }, { "meta", META }, { "mglyph", MGLYPH },
	{ "mi", MI }, { "mn", MN }, { "mo", MO }, { "ms", MS }, { "mtext", MTEXT },
	{ "nobr", NOBR }, { "noembed", NOEMBED }, { "noframes", NOFRAMES },
	{ "noscript", NOSCRIPT }, { "object", OBJECT }, { "ol", OL }, { "optgroup", OPTGROUP },
	{ "option", OPTION }, { "output", OUTPUT }, { "p", P }, { "param", PARAM },
	{ "plaintext", PLAINTEXT }, { "pre", PRE }, { "s", S }, { "script", SCRIPT },
	{ "select", SELECT }, { "small", SMALL }, { "spacer", SPACER }, { "strike", STRIKE },
	{ "strong", STRONG }, { "style", STYLE }, { "summary", SUMMARY }, { "svg", SVG },
	{ "table", TABLE }, { "tbody", TBODY }, { "td", TD }, { "textarea", TEXTAREA },
	{ "tfoot", TFOOT }, { "th", TH }, { "thead", THEAD }, { "title", TITLE }, { "tr", TR },
	{ "tt", TT }, { "u", U }, { "ul", UL }, { "wbr", WBR }, { "xmp", XMP },
};

/* ASCII case-insensitive equality of exactly n bytes, with a's NUL terminator at n. */
static int et_ci_match(const char *kw, const char *s, size_t n)
{
	size_t i;
	for (i = 0; i < n; i++) {
		unsigned char a = (unsigned char) kw[i];
		unsigned char b = (unsigned char) s[i];
		if (a == '\0')
			return 0;			/* keyword shorter than n */
		if (a >= 'A' && a <= 'Z') a = (unsigned char)(a - 'A' + 'a');
		if (b >= 'A' && b <= 'Z') b = (unsigned char)(b - 'A' + 'a');
		if (a != b)
			return 0;
	}
	return kw[n] == '\0';				/* and keyword length == n */
}

const struct element_type_map *
hubbub_element_type_generated_lookup(const char *str, size_t len)
{
	size_t i;
	for (i = 0; i < sizeof(wordlist) / sizeof(wordlist[0]); i++) {
		if (et_ci_match(wordlist[i].name, str, len))
			return &wordlist[i];
	}
	return NULL;
}
